The implementation follows a two-phase traversal strategy that mirrors standard social media feed behavior:
\begin{enumerate}
    \item The walker first visits all tweets directly connected to the user's profile, using the directional traversal syntax \lstinline[basicstyle=\fontsize{9}{10}]{-->} to select edges where the profile is the source node
    \item It then traverses the social graph via \lstinline[basicstyle=\fontsize{9}{10}]{Follow} edges to access content from followed accounts, specifically following edges where the current profile is the source node and the followed profiles are destination nodes
\end{enumerate}

\paragraph{Traversal Logic (Walker)}
The \lstinline[basicstyle=\fontsize{9}{10}]{load_feed} walker encapsulates:
\begin{itemize}
    \item Profile resolution (inherited from its parent walker)
    \item Graph traversal strategy with context-sensitive directional constraints
    \item State management for query parameters and result accumulation
    \item Final result aggregation and reporting
\end{itemize}

\paragraph{Content Processing (Node)}
The Tweet node's \lstinline[basicstyle=\fontsize{9}{10}]{get} ability implements:
\begin{itemize}
    \item Self-contained tweet metadata collection
    \item Semantic similarity calculation against the search query
    \item Result contribution to the walker's accumulated state
\end{itemize}

\begin{enumerate}
    \item \textbf{Walker-to-Node Data Flow}: The Tweet node accesses the search query parameter via \lstinline[basicstyle=\fontsize{9}{10}]{here.search_query}
    \item \textbf{Node-to-Walker Data Flow}: The Tweet node contributes to the result set via \lstinline[basicstyle=\fontsize{9}{10}]{here.results.append()}
\end{enumerate}

\subsubsection{Object Creation}
For a standard object construction:
\begin{align}
\frac{\text{new } \tau_{\text{obj}}()}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma' = (O \cup \{o\}, N, E, W, Q, L, A, S)} \text{ [O-CREATION]}
\end{align}
where \( o \) is a fresh instance of type \( \tau_{\text{obj}} \).

\subsubsection{Node Creation}
For node construction:
\begin{align}
\frac{\text{new } \tau_{\text{node}}()}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma' = (O \cup \{n\}, N \cup \{n\}, E, W, Q, L, A, S)} \text{ [N-CREATION]}
\end{align}
where \( n \) is a fresh instance of type \( \tau_{\text{node}} \).

\subsubsection{Edge Creation}
For edge construction between existing nodes, enforcing the instantiation constraints from Section:
\begin{align}
\frac{
\begin{array}{c}
\text{new } \tau_{\text{edge}}(n_{\text{src}}, n_{\text{dst}}) \\
n_{\text{src}}, n_{\text{dst}} \in N
\end{array}
}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma' = (O \cup \{e\}, N, E \cup \{e\}, W, Q, L, A, S)} \text{ [E-CREATION]}
\end{align}
where \( e = (n_{\text{src}}, n_{\text{dst}}) \) is a fresh edge instance connecting nodes \( n_{\text{src}} \) and \( n_{\text{dst}} \).

\subsubsection{Walker Creation}
For walker construction in inactive state:
\begin{align}
&\frac{\text{new } \tau_{\text{walker}}()}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma'} \text{ [W-CREATION]}\\
&\text{where } \sigma' = (O \cup \{w\}, N, E, W \cup \{w\}, Q[w \mapsto \langle\rangle], L[w \mapsto \emptyset], A[w \mapsto \text{inactive}], S) \nonumber
\end{align}
where \( w \) is a fresh walker instance, \( Q[w \mapsto \langle\rangle] \) assigns an empty queue to \( w \), \( L[w \mapsto \emptyset] \) indicates the walker has no location, and \( A[w \mapsto \text{inactive}] \) sets the walker's initial state to inactive, aligning with the inactive walker state defined in Section.

\subsubsection{Node Deletion}
For node deletion with cascade to connected edges, implementing the lifecycle management from Section:
\begin{align}
&\frac{
\begin{array}{c}
\text{delete}(n) \\
n \in N \\
E_n = \{e \in E \mid e = (n, n') \lor e = (n', n) \text{ for any } n' \in N\}
\end{array}
}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma'} \text{ [N-DELETION]}\\
&\text{where } \sigma' = (O \setminus (\{n\} \cup E_n), N \setminus \{n\}, E \setminus E_n, W, Q', L', A', S') \nonumber
\end{align}
where:
\begin{itemize}
    \item \( E_n \) is the set of all edges connected to node \( n \)
    \item \( Q' \) is \( Q \) with all references to \( n \) and edges in \( E_n \) removed from all queues
    \item \( L' \) is \( L \) updated to reflect that walkers at \( n \) or any edge in \( E_n \) are now at \( \emptyset \) and inactive
    \item \( A' \) is \( A \) updated to mark those walkers as inactive
    \item \( S' \) is \( S \) with mappings for deleted edges removed
\end{itemize}

\subsubsection{Spawn Operation on Node}
For spawning a walker at a specific node, implementing the Spawn Operator semantics from Section :
\begin{align}
&\frac{
\begin{array}{c}
w \Rightarrow n \\
w \in W \\
n \in N \\
A(w) = \text{inactive}
\end{array}
}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma'} \text{ [SPAWN-NODE]}\\
&\text{where } \sigma' = (O, N, E, W, Q[w \mapsto \langle\rangle], L[w \mapsto n], A[w \mapsto \text{active}], S) \nonumber
\end{align}
where \( L[w \mapsto n] \) updates walker \( w \)'s location to node \( n \), and \( A[w \mapsto \text{active}] \) activates the walker.

\subsubsection{Spawn Operation on Edge}
For spawning a walker on a specific edge with default direction (from source to destination):
\begin{align}
&\frac{
\begin{array}{c}
w \Rightarrow e \\
w \in W \\
e = (n_{\text{src}}, n_{\text{dst}}) \in E \\
A(w) = \text{inactive}
\end{array}
}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma'} \text{ [SPAWN-EDGE]}\\
&\text{where } \sigma' = (O, N, E, W, Q[w \mapsto \langle n_{\text{dst}} \rangle], L[w \mapsto e], A[w \mapsto \text{active}], S[w, e \mapsto n_{\text{src}}]) \nonumber
\end{align}
where:
\begin{itemize}
    \item \( L[w \mapsto e] \) updates walker \( w \)'s location to edge \( e \)
    \item \( A[w \mapsto \text{active}] \) activates the walker
    \item \( S[w, e \mapsto n_{\text{src}}] \) records the entry node as the source node for the walker's edge traversal
    \item \( Q[w \mapsto \langle n_{\text{dst}} \rangle] \) automatically adds the destination node to the walker's queue
\end{itemize}

\subsubsection{Spawn Operation on Edge with Explicit Entry Node}
For spawning a walker on a specific edge with an explicitly specified entry node, supporting the directional edge traversal described in Section :
\begin{align}
&\frac{
\begin{array}{c}
w \Rightarrow (e, n_{\text{entry}}) \\
w \in W \\
e = (n_{\text{src}}, n_{\text{dst}}) \in E \\
n_{\text{entry}} \in \{n_{\text{src}}, n_{\text{dst}}\} \\
A(w) = \text{inactive}
\end{array}
}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma'} \text{ [SPAWN-EDGE-DIR]}\\
&\text{where } \sigma' = (O, N, E, W, Q', L[w \mapsto e], A[w \mapsto \text{active}], S[w, e \mapsto n_{\text{entry}}]) \nonumber
\end{align}
where:
\begin{itemize}
    \item \( L[w \mapsto e] \) updates walker \( w \)'s location to edge \( e \)
    \item \( A[w \mapsto \text{active}] \) activates the walker
    \item \( S[w, e \mapsto n_{\text{entry}}] \) records the explicit entry node for the walker's edge traversal
    \item \( Q' = \begin{cases} 
        Q[w \mapsto \langle n_{\text{dst}} \rangle] & \text{if } n_{\text{entry}} = n_{\text{src}} \\
        Q[w \mapsto \langle n_{\text{src}} \rangle] & \text{if } n_{\text{entry}} = n_{\text{dst}}
    \end{cases} \) automatically adds the appropriate destination node to the walker's queue
\end{itemize}

\subsubsection{Spawn Operation on Path}
For spawning a walker on a path collection, as specified in Section  and Section :
\begin{align}
&\frac{
\begin{array}{c}
w \Rightarrow \mathcal{P} \\
\mathcal{P} = [p_1, p_2, \ldots, p_k] \\
p_1 \in N \cup E \\
w \in W \\
A(w) = \text{inactive}
\end{array}
}{\sigma = (O, N, E, W, Q, L, A, S) \Rightarrow \sigma'} \text{ [SPAWN-PATH]}\\
&\text{where } \sigma' = \begin{cases}
\begin{aligned}
&(O, N, E, W, Q[w \mapsto \langle p_2, \ldots, p_k \rangle], \\
&\quad L[w \mapsto p_1], A[w \mapsto \text{active}], S)
